-- Bank transfer with proper transaction + row locking

BEGIN;

  -- Lock BOTH rows in a consistent order (by id) to avoid deadlocks with other transfers
  SELECT balance FROM accounts WHERE id IN (:alice, :bob) ORDER BY id FOR UPDATE;

  -- Verify Alice has enough — INSIDE the transaction (with the lock held)
  DO $$
    DECLARE alice_balance NUMERIC;
    BEGIN
      SELECT balance INTO alice_balance FROM accounts WHERE id = :alice FOR UPDATE;
      IF alice_balance < 100 THEN
        RAISE EXCEPTION 'Insufficient funds';
      END IF;
    END
  $$;

  UPDATE accounts SET balance = balance - 100 WHERE id = :alice;
  UPDATE accounts SET balance = balance + 100 WHERE id = :bob;

  -- Also record for the audit log — same transaction so it's atomic
  INSERT INTO transfers(from_id, to_id, amount) VALUES (:alice, :bob, 100);

COMMIT;

-- On any error inside — ROLLBACK; money never moves. Perfect.

-- What if we DIDN'T use FOR UPDATE?
-- Concurrent transfer of 90 from Alice: both txs read balance=100, both compute new balance=100-100=0
-- (or 100-90=10), and Alice ends up overdrawn or arithmetic breaks. This is 'lost update'.
-- FOR UPDATE serializes access to the row — the second tx waits for the first to commit,
-- then re-reads the balance (which is now 0), and correctly refuses.

-- Alternative to FOR UPDATE — SERIALIZABLE isolation:
-- BEGIN ISOLATION LEVEL SERIALIZABLE;
--   (same SELECT/UPDATE, no FOR UPDATE needed)
-- COMMIT;
-- On conflict, Postgres aborts one tx — the app must retry.

-- Alternative — optimistic concurrency with a version column:
-- UPDATE accounts SET balance = ?, version = version + 1
-- WHERE id = :alice AND version = :read_version;
-- If rowcount = 0, the row changed underneath you — retry.

-- Rule: pick ONE consistency strategy and use it consistently.
